/* Мини-библиотека SignalR для учебных целей */
let signalR = (function() {
    return {
        HubConnectionBuilder: function() {
            this.url = "";
            this.tokenFactory = () => "";
            this.withUrl = function(url, options) {
                this.url = url;
                if (options && options.accessTokenFactory) this.tokenFactory = options.accessTokenFactory;
                return this;
            };
            this.build = function() {
                let url = this.url;
                const tokenFactory = this.tokenFactory;
                const handlers = {};
                let socket;

                return {
                    on: function(name, callback) { handlers[name] = callback; },
                    start: function() {
                        const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
                        const wsUrl = protocol + "//" + window.location.host + url + "?access_token=" + tokenFactory();
                        socket = new WebSocket(wsUrl);
                        socket.onmessage = function(e) {
                            // Обработка SignalR протокола (упрощенно)
                            const rawData = e.data.split('\u001e')[0];
                            if (!rawData) return;
                            const data = JSON.parse(rawData);
                            if (data.type === 1 && handlers[data.target]) {
                                handlers[data.target].apply(null, data.arguments);
                            }
                        };
                        return new Promise((resolve, reject) => {
                            socket.onopen = () => {
                                socket.send('{"protocol":"json","version":1}\u001e');
                                resolve();
                            };
                            socket.onerror = (err) => reject("Ошибка связи");
                        });
                    },
                    invoke: function(name, user, msg) {
                        const packet = {type: 1, target: name, arguments: [user, msg]};
                        socket.send(JSON.stringify(packet) + '\u001e');
                    }
                };
            };
            return this;
        }
    };
})();
